  7	function parseStoryImplementorHandle(content: string) {
  8	  const match = content.match(
  9	    /## Current Continuation Handles\n- Story Implementor:\n  - Story: (?<story>[^\n]+)\n  - Provider: (?<provider>[^\n]+)\n  - Session ID: (?<sessionId>[^\n]+)\n  - Result Artifact: (?<artifact>[^\n]+)/
 10	  );
 11	
 12	  expect(match?.groups).toBeDefined();
 13	
 14	  return {
 15	    story: match?.groups?.story,
 16	    provider: match?.groups?.provider,
 17	    sessionId: match?.groups?.sessionId,
 18	    artifact: match?.groups?.artifact,
 19	  };
 20	}
